import{_ as e,c as i,o as a,a3 as l}from"./chunks/framework.6s30bTua.js";const h=JSON.parse('{"title":"Unified Modelling Language (UML)","description":"Unified Modelling Language (UML) is a general-purpose, developmental modelling language","frontmatter":{"title":"Unified Modelling Language (UML)","description":"Unified Modelling Language (UML) is a general-purpose, developmental modelling language"},"headers":[],"relativePath":"Concepts/UML.md","filePath":"Concepts/UML.md","lastUpdated":1690829560000}'),t={name:"Concepts/UML.md"},s=l('<h1 id="unified-modelling-language-uml" tabindex="-1">Unified Modelling Language (UML) <a class="header-anchor" href="#unified-modelling-language-uml" aria-label="Permalink to &quot;Unified Modelling Language (UML)&quot;">​</a></h1><p>UML is a general-purpose, developmental modelling language that is intended to provide a standard way to visualize the design of a system</p><h2 id="model" tabindex="-1">Model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;Model&quot;">​</a></h2><p>Model is a partial abstract representation of a real-world system</p><ul><li>An inexpensive way to analyze, communicate, test, and document our understanding of the system</li></ul><p>Types of Models:</p><ol><li><p>Computational</p><ul><li>Computer simulations representing time-varying behaviour of a system</li></ul></li><li><p>Analytical:</p><ul><li>Mathematical models of relationships among variables in a system</li></ul></li><li><p>Non-Analytical/descriptive:</p><ul><li><p>Describe components and their relationships in a system</p></li><li><p>Models in Software can be categorized into 2 groups:</p><ol><li><p>Data Models: like Entity Relationship models,etc.</p></li><li><p>Application Models: UML models, SysML models, BPMN models, etc.</p></li></ol></li></ul></li></ol><h2 id="types-of-uml" tabindex="-1">Types of UML <a class="header-anchor" href="#types-of-uml" aria-label="Permalink to &quot;Types of UML&quot;">​</a></h2><ol><li><p><em>Structure</em>: Represents static view of the system and its components</p><ol><li>Class diagram</li><li>Component diagram</li><li>Object diagram</li><li>Composite structure diagram</li><li>Package diagram</li><li>Deployment diagram</li></ol></li><li><p><em>behaviour</em>: Represents dynamic view of the system and its components</p><ol><li><p>Use case diagram:</p><ul><li><p>Capture high-level functionality of a system using notations for actors, use cases, and relationships among them</p></li><li><p>Often drawn by business analysts to depict the summary all use cases in a system</p></li><li><p>Key elements:</p><ul><li><p>Use cases:</p><ul><li>Notation is a bubble that carries use case title</li></ul></li><li><p>Systems</p></li><li><p>Actors:</p><ul><li><p>A user&#39;s role with respect to the system</p></li><li><p>Maybe a human or another system</p></li><li><p><em>Primary actor</em>: whose goal is fulfilled by the use case</p></li><li><p><em>Secondary actor</em>: who is involved in the use case</p><ul><li>Often an external system</li></ul></li></ul></li><li><p>Associations</p></li></ul></li></ul></li><li><p>Activity diagram</p></li><li><p>State machine diagram</p></li><li><p>Interaction</p></li></ol></li><li><p><em>Interaction</em> (part of <em>behaviour</em>): Represents interaction, among components of the system and between system and external actors</p><ol><li>Sequence diagram</li><li>Communication diagram</li><li>Timing diagram</li><li>interaction overview diagram</li></ol></li></ol><h2 id="class-diagram" tabindex="-1">Class Diagram <a class="header-anchor" href="#class-diagram" aria-label="Permalink to &quot;Class Diagram&quot;">​</a></h2><ul><li>Class Name</li><li>Attributes</li><li>behaviours</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><p><a href="https://www.omg.org/spec/UML/" target="_blank" rel="noreferrer">Unified Modelling Language (UML) specification 2.5</a></p><ul><li>controlled by Object Management Group (OMG)</li><li>Releases: UML-1 (1997), UML-2 (2005), UML-2.5 (2015)</li></ul></li><li><p>UML Distilled by Martin Fowler</p></li><li><p>Applying UML and Patterns by Craig Larman</p></li></ul>',13),n=[s];function o(r,p,d,m,u,c){return a(),i("div",null,n)}const f=e(t,[["render",o]]);export{h as __pageData,f as default};
